text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "meeting_code": "PUBLIC_MEETING_SMOKE",
        "project": "UI Theme Package Release Readiness",
        "decision": "공개 릴리스 목표일은 smoke 테스트 통과 시 금요일 15:00 KST로 확정되었다."
      },
      {
        "decision": "packageName 불일치 처리 기준은 'smoke-theme-pack.mjs에서 무시 처리'가 아니라 '패키지 설정을 우선 확인'하는 방식으로 확정."
      },
      {
        "decision": "패키지 contract 자체가 잘못된 경우에만 해당 스크립트 검토를 고려한다."
      },
      {
        "decision": "Minjun: 금요일 10:00 KST까지 smoke test를 재실행하고 결과 공유(확정)."
      },
      {
        "decision": "Doyun: 금요일 12:00 KST까지 action_items.md에 실패 triage note 작성(확정)."
      },
      {
        "decision": "Hara: Minjun이 smoke 결과를 게시한 후 생성된 tarball 경로를 확인한다."
      },
      {
        "decision": "참가자는 특정 고객/외부 파트너를 언급하지 않았고, 회의록에는 고객 관련 항목이 없다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "Hara의 제안: smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "거절"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 공개 릴리스 목표 제안",
        "status": "내부 stretch goal로만 유지, 공개 릴리스 목표 아님"
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로가 잘못되면 배포 지연 가능성"
      },
      {
        "risk": "README install steps가 오래되면 릴리스 노트/안내가 사용자에게 오해를 줄 가능성"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부"
      },
      {
        "question": "README install steps 리뷰 담당자/확인 주체 미지정"
      }
    ],
    "non_decisions": [
      "README install steps를 목요일에 검토하자는 제안은 있었으나 담당자 미배정 상태.",
      "Hara의 tarball 경로 확인은 Minjun 결과 게시 후 수행이지만, 구체 마감 시각은 미확정."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test 재실행 후 금요일 10:00 KST 전 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 게시 후 생성된 tarball 경로 확인",
      "due": "Minjun 결과 게시 후(기한 미정)",
      "status": "확정",
      "source_certainty": "중간"
    },
    {
      "owner": null,
      "task": "README install steps 검토(요청만 있었으나 소유자 미지정)",
      "due": "목표: 목요일(요구사항 수준), 책임자 미정",
      "status": "미할당",
      "source_certainty": "중간"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전에 Minjun의 smoke test 재실행 결과 수신 여부 및 pass/fail 상태",
      "실패 시 Doyun의 triage note 적시 작성 여부",
      "Hara의 tarball path 확인 결과(경로 일치 여부)",
      "최종 릴리스 승인 권한자 합의(오픈 질문 해결)",
      "릴리스 노트에 내부 stretch goal 노출 여부 결정"
    ],
    "what_not_to_invent": [
      "고객명/외부 파트너명",
      "예산 관련 수치",
      "보안 사고/운영 장애/법무 승인 언급",
      "확정되지 않은 owner, deadline, 책임자(미지정 항목)",
      "README 담당자, 스프린트 세부 일정의 상세한 추가 사실"
    ]
  },
  "non_invention_rules": [
    "회의 원문에 없는 고객/외부 협력사 정보는 작성하지 않는다.",
    "예산, 보안 사고, 운영 장애, 법무 승인 필요성 같은 항목은 추론하여 생성하지 않는다.",
    "owner 또는 마감일이 미정인 항목은 임의로 채우지 않는다.",
    "sprint/릴리스 세부 목표는 공개 목표와 내부 stretch goal을 구분하여 다룬다.",
    "허용된 사실만 기록하고, '미확인' 항목은 open question 또는 미할당으로 표시한다."
  ]
}
